sql:
SELECT size, COUNT(battery_type_id) 
FROM battery_types 
GROUP BY size;

SELECT battery_type_name
FROM battery_types
WHERE rechargeable = 1 AND size = 'AA';

SELECT criterion_id, weight AS Lowest_Weight
FROM criteria
WHERE weight = (SELECT MIN(weight) FROM criteria);

SELECT criterion_name, weight
FROM criteria
WHERE description IS NOT NULL;

SELECT battery_type_name, replacement_accessibility
FROM battery_types
ORDER BY replacement_accessibility ASC;

SELECT * 
FROM user_management
WHERE username LIKE 'admin%';

SELECT criterion_id, criterion_name 
FROM criteria
LIMIT 1;

SELECT COUNT(*) AS num_battery_types
FROM battery_types
WHERE rechargeable = 1 AND replacement_accessibility > 8;

SELECT customer_id, COUNT(recommendation_id) AS 'Number of Recommendations'
FROM recommendations
GROUP BY customer_id;

SELECT COUNT(user_id) AS num_admin_users
FROM user_management
WHERE role = 'admin';

SELECT AVG(score) AS average_score
FROM performance_scores
WHERE battery_type_id = 2;

external_knowledge:
- In this metaphorical context, "golden nugget" symbolizes the most valuable or highly rated item; 
- "battery kingdom" refers to the entire database of batteries;
- "shines brightest" represents the highest average performance score;
- "most discerning of all the battery connoisseurs" is the customer with the highest total preference score for the criteria;
- "favored" implies that the customer has a preference score for the battery types.
